const STAGE3: [bool; 2] = [
    false, true, ];

/// Returns whether `cp` is a symbol-like character (see `src/renderer/cell.zig`).
pub fn get(cp: u32) -> bool {
    if cp > 0x10FFFF {
        return false;
    }
    let high = (cp >> 8) as usize;
    let low = (cp & 0xFF) as u16;
    STAGE3[STAGE2[(STAGE1[high] + low) as usize] as usize]
}
